package com.restaurantcraft.util; import net.minecraftforge.items.ItemStackHandler; public class RestaurantInventoryUtil { public static boolean isEmpty(ItemStackHandler h){for(int i=0;i<h.getSlots();i++)if(!h.getStackInSlot(i).isEmpty())return false;return true;} public static void clear(ItemStackHandler h){for(int i=0;i<h.getSlots();i++)h.setStackInSlot(i,net.minecraft.world.item.ItemStack.EMPTY);} public static void copy(ItemStackHandler a, ItemStackHandler b){clear(b);for(int i=0;i<Math.min(a.getSlots(),b.getSlots());i++)b.setStackInSlot(i,a.getStackInSlot(i).copy());} }
